      "purpose": "Classify changed files to determine which validation gates are required.",
      "rules": [
        {
          "ifPathMatches": ["**/*.ts", "**/*.tsx", "**/*.js", "**/*.jsx", "**/*.mjs", "**/*.cjs"],
          "require": ["js_ts_validation"]
        },
        {
          "ifPathMatches": ["**/*.sql", "**/migrations/**", "**/*migration*"],
          "require": ["sql_migration_validation"]
        },
        {
          "ifPathMatches": ["workers/**", "**/worker/**", "**/cloudflare/**", "**/wrangler.toml", "src/worker/**"],
          "require": ["cloudflare_worker_validation"]
        },
        {
          "ifPathMatches": ["dashboard/**", "app/**", "web/**", "**/*.tsx", "**/*.jsx"],
          "require": ["dashboard_browser_validation"]
        },
        {
          "ifPathMatches": ["**/*"],
          "require": ["exclude_model_keys_validation"]
        }
      ]
    },
